sql:
SELECT province_name
FROM provinces
WHERE province_id = 0;

SELECT countries.country_id, countries.country_name, provinces.province_name
FROM countries
INNER JOIN provinces ON countries.country_id = provinces.country_id;

SELECT province_name, population
FROM provinces
WHERE population > (SELECT AVG(population) FROM provinces);

SELECT case_id, location_type
FROM case_geo_locations
WHERE location_type = 'city';

SELECT case_id, confirmed
FROM cases
WHERE confirmed > (SELECT AVG(confirmed) FROM cases);

SELECT COUNT(*) 
FROM case_contacts 
WHERE contact_type = 'family';

external_knowledge:
- "populous" refers to provinces with large numbers of people;
- "confirmed cases" refer to officially recorded instances of an illness;
- "fatalities" refer to the number of deaths caused by an illness.

